--
-- Table structure for table `inspections`
--

CREATE TABLE `inspections` (
  `id` bigint(20) UNSIGNED NOT NULL,
  `user_id` bigint(20) UNSIGNED NOT NULL COMMENT 'Foreign key to the user who booked the inspection.',
  `agent_id` bigint(20) UNSIGNED NOT NULL COMMENT 'Foreign key to the agent being booked.',
  `property_id` bigint(20) UNSIGNED DEFAULT NULL COMMENT 'Foreign key to the property to be inspected. Can be null if booking is general.',
  `transaction_id` bigint(20) UNSIGNED DEFAULT NULL COMMENT 'Foreign key to the transaction record.',
  `inspection_date` date NOT NULL COMMENT 'The scheduled date of the inspection.',
  `inspection_time` time NOT NULL COMMENT 'The scheduled time of the inspection.',
  `status` enum('scheduled','rescheduled','confirmed','completed','cancelled','no_show') NOT NULL DEFAULT 'scheduled' COMMENT 'The current status of the inspection appointment.',
  `reason_cancellation` text DEFAULT NULL COMMENT 'Users reason for cancelling the inspection even after payment ',
  `reschedule_date` date DEFAULT NULL COMMENT 'The date the inspection was rescheduled to.',
  `reschedule_time` time DEFAULT NULL COMMENT 'The time the inspection was rescheduled to.',
  `amount` decimal(10,2) NOT NULL DEFAULT 5000.00 COMMENT 'The fee charged for the inspection.',
  `payment_status` enum('pending','paid','refunded') NOT NULL DEFAULT 'pending' COMMENT 'The status of the payment for the inspection.',
  `payment_method` varchar(255) DEFAULT NULL COMMENT 'The method used for payment.',
  `created_at` timestamp NULL DEFAULT current_timestamp(),
