CREATE TABLE `properties` (
  `id` int(10) UNSIGNED NOT NULL,
  `property_id` int(10) UNSIGNED DEFAULT NULL,
  `agent_id` bigint(20) UNSIGNED NOT NULL,
  `title` varchar(255) NOT NULL,
  `type` varchar(50) NOT NULL,
  `location` varchar(255) NOT NULL,
  `latitude` decimal(9,6) DEFAULT NULL,
  `longitude` decimal(9,6) DEFAULT NULL,
  `amenities` text DEFAULT NULL,
  `listing_type` enum('For Sale','For Rent','Sold','Rented') NOT NULL DEFAULT 'For Sale',
  `price` decimal(20,2) NOT NULL DEFAULT 0.00,
  `beds` int(11) NOT NULL DEFAULT 0,
  `baths` int(11) NOT NULL DEFAULT 0,
  `sqft` varchar(20) DEFAULT NULL,
  `description` text DEFAULT NULL,
  `address` text DEFAULT NULL,
  `inspection_fee` decimal(10,2) NOT NULL DEFAULT 0.00,
  `status` enum('Active','Inactive') NOT NULL DEFAULT 'Active',
  `images` text DEFAULT NULL,
  `is_featured` tinyint(1) NOT NULL DEFAULT 0,
  `is_verified` tinyint(1) NOT NULL DEFAULT 0,
  `created_at` timestamp NULL DEFAULT NULL,
  `updated_at` timestamp NULL DEFAULT NULL,
  `view_count` int(11) UNSIGNED NOT NULL DEFAULT 0 COMMENT 'Number of times property details viewed',
  `inspection_booking_count` int(11) UNSIGNED NOT NULL DEFAULT 0 COMMENT 'Number of times property booked for inspection',
  `leads_count` int(11) UNSIGNED NOT NULL DEFAULT 0 COMMENT 'Number of times property saved (leads generated)'
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;

