--
-- Table structure for table `transfer_recipients`
--

CREATE TABLE `transfer_recipients` (
  `id` bigint(20) UNSIGNED NOT NULL,
  `user_id` bigint(20) UNSIGNED NOT NULL COMMENT 'ID of user or agent',
  `user_type` enum('user','agent') NOT NULL DEFAULT 'agent' COMMENT 'user = cribs_arena, agent = cribs_agents',
  `recipient_code` varchar(100) NOT NULL COMMENT 'Paystack recipient code (RCP_xxxxx)',
  `bank_code` varchar(10) NOT NULL COMMENT 'Bank code from Paystack',
  `bank_name` varchar(100) NOT NULL COMMENT 'Bank name for display',
  `account_number` varchar(20) NOT NULL,
  `account_name` varchar(255) NOT NULL COMMENT 'Verified account name from Paystack',
  `is_default` tinyint(1) NOT NULL DEFAULT 1 COMMENT 'Primary withdrawal account',
  `is_active` tinyint(1) NOT NULL DEFAULT 1,
  `created_at` timestamp NULL DEFAULT NULL,
  `updated_at` timestamp NULL DEFAULT NULL
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;

