--
-- Table structure for table `wallets`
--

CREATE TABLE `wallets` (
  `id` bigint(20) UNSIGNED NOT NULL,
  `user_id` bigint(20) UNSIGNED NOT NULL COMMENT 'ID of user or agent',
  `user_type` enum('user','agent') NOT NULL COMMENT 'user = cribs_arena, agent = cribs_agents',
  `available_balance` decimal(12,2) NOT NULL DEFAULT 0.00 COMMENT 'Withdrawable balance',
  `pending_balance` decimal(12,2) NOT NULL DEFAULT 0.00 COMMENT 'In escrow, not yet released',
  `total_earned` decimal(12,2) NOT NULL DEFAULT 0.00 COMMENT 'Lifetime earnings',
  `total_withdrawn` decimal(12,2) NOT NULL DEFAULT 0.00 COMMENT 'Lifetime withdrawals',
  `currency` varchar(3) NOT NULL DEFAULT 'NGN',
  `created_at` timestamp NULL DEFAULT NULL,
  `updated_at` timestamp NULL DEFAULT NULL
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;

