--
-- Table structure for table `wallet_transactions`
--

CREATE TABLE `wallet_transactions` (
  `id` bigint(20) UNSIGNED NOT NULL,
  `wallet_id` bigint(20) UNSIGNED NOT NULL,
  `user_id` bigint(20) UNSIGNED NOT NULL,
  `user_type` enum('user','agent') NOT NULL,
  `transaction_type` enum('deposit','withdrawal','refund','escrow_release','escrow_hold','platform_fee','subscription') NOT NULL,
  `amount` decimal(12,2) NOT NULL,
  `fee` decimal(10,2) DEFAULT 0.00 COMMENT 'Platform or Paystack fees',
  `net_amount` decimal(12,2) NOT NULL COMMENT 'Amount after fees',
  `balance_before` decimal(12,2) NOT NULL,
  `balance_after` decimal(12,2) NOT NULL,
  `currency` varchar(3) NOT NULL DEFAULT 'NGN',
  `reference` varchar(100) NOT NULL,
  `paystack_reference` varchar(100) DEFAULT NULL COMMENT 'Paystack transaction/transfer reference',
  `recipient_code` varchar(100) DEFAULT NULL COMMENT 'For withdrawals',
  `related_transaction_id` bigint(20) UNSIGNED DEFAULT NULL COMMENT 'Links to original transactions table',
  `related_inspection_id` bigint(20) UNSIGNED DEFAULT NULL,
  `status` enum('pending','processing','success','failed','reversed') NOT NULL DEFAULT 'pending',
  `failure_reason` text DEFAULT NULL,
  `description` varchar(500) DEFAULT NULL,
  `metadata` longtext CHARACTER SET utf8mb4 COLLATE utf8mb4_bin DEFAULT NULL COMMENT 'Additional data as JSON' CHECK (json_valid(`metadata`)),
  `created_at` timestamp NULL DEFAULT NULL,
  `updated_at` timestamp NULL DEFAULT NULL
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;

